/*!40101 SET CHARACTER_SET_CLIENT=utf8mb4 */;
-- ============================================================
--  Script DDL + DML — Surveillance des Maladies Infectieuses
--  Source : WHO Global Health Observatory
--  Généré automatiquement à partir des fichiers CSV WHO
-- ============================================================

CREATE DATABASE IF NOT EXISTS surveillance_maladies
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

USE surveillance_maladies;

SET FOREIGN_KEY_CHECKS = 0;

-- ============================================================
--  DDL — Structure des tables
-- ============================================================

CREATE TABLE IF NOT EXISTS REGION_OMS (
    id_region   INT          AUTO_INCREMENT PRIMARY KEY,
    nom_region  VARCHAR(100) NOT NULL,
    code_region CHAR(6)      NOT NULL,
    CONSTRAINT uq_region_nom  UNIQUE (nom_region),
    CONSTRAINT uq_region_code UNIQUE (code_region)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS PAYS (
    id_pays   INT          AUTO_INCREMENT PRIMARY KEY,
    nom       VARCHAR(150) NOT NULL,
    code_iso  CHAR(3)      NOT NULL,
    continent VARCHAR(50)  NOT NULL,
    id_region INT          NOT NULL,
    CONSTRAINT uq_pays_iso    UNIQUE (code_iso),
    CONSTRAINT chk_code_iso   CHECK (CHAR_LENGTH(code_iso) = 3),
    CONSTRAINT fk_pays_region FOREIGN KEY (id_region)
        REFERENCES REGION_OMS(id_region)
        ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE INDEX idx_pays_region ON PAYS(id_region);

CREATE TABLE IF NOT EXISTS MALADIE (
    id_maladie      INT          AUTO_INCREMENT PRIMARY KEY,
    nom             VARCHAR(150) NOT NULL,
    categorie       VARCHAR(100) NOT NULL,
    agent_pathogene VARCHAR(150),
    CONSTRAINT uq_maladie_nom UNIQUE (nom)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS INDICATEUR (
    id_indicateur   INT          AUTO_INCREMENT PRIMARY KEY,
    code_indicateur VARCHAR(50)  NOT NULL,
    libelle         VARCHAR(255) NOT NULL,
    unite           VARCHAR(50),
    description     TEXT,
    CONSTRAINT uq_indicateur_code UNIQUE (code_indicateur)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS SOURCE_DONNEES (
    id_source       INT          AUTO_INCREMENT PRIMARY KEY,
    nom             VARCHAR(200) NOT NULL,
    url             VARCHAR(500),
    date_extraction DATE         NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS MESURE (
    id_mesure     INT           AUTO_INCREMENT PRIMARY KEY,
    valeur        DECIMAL(10,2) NOT NULL,
    annee         YEAR          NOT NULL,
    id_pays       INT           NOT NULL,
    id_maladie    INT           NOT NULL,
    id_indicateur INT           NOT NULL,
    id_source     INT           NOT NULL,
    CONSTRAINT chk_valeur_positive  CHECK (valeur >= 0),
    CONSTRAINT chk_annee_range      CHECK (annee >= 1990 AND annee <= 2026),
    CONSTRAINT fk_mesure_pays       FOREIGN KEY (id_pays)
        REFERENCES PAYS(id_pays)
        ON DELETE RESTRICT ON UPDATE CASCADE,
    CONSTRAINT fk_mesure_maladie    FOREIGN KEY (id_maladie)
        REFERENCES MALADIE(id_maladie)
        ON DELETE RESTRICT ON UPDATE CASCADE,
    CONSTRAINT fk_mesure_indicateur FOREIGN KEY (id_indicateur)
        REFERENCES INDICATEUR(id_indicateur)
        ON DELETE RESTRICT ON UPDATE CASCADE,
    CONSTRAINT fk_mesure_source     FOREIGN KEY (id_source)
        REFERENCES SOURCE_DONNEES(id_source)
        ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE INDEX idx_mesure_pays_maladie  ON MESURE(id_pays, id_maladie);
CREATE INDEX idx_mesure_annee         ON MESURE(annee);
CREATE INDEX idx_mesure_indicateur    ON MESURE(id_indicateur);
CREATE INDEX idx_mesure_maladie_annee ON MESURE(id_maladie, annee);

